#include <stdio.h>
int main() {
    int K;
    scanf("%d", &K);
    int **arrays = (int **)malloc(K * sizeof(int *));
    for (int i = 0; i < K; i++) {
        int si;
        scanf("%d", &si);
        arrays[i] = (int *)malloc(si * sizeof(int));
        for (int j = 0; j < si; j++) {
            scanf("%d", &arrays[i][j]);
        }
    }
    int M;
    scanf("%d", &M);
    for (int i = 0; i < M; i++) {
        int a, b;
        scanf("%d %d", &a, &b);
        a--; b--;
        long long sad = 0;
        int sa = 0, sb = 0;
        while (sa < sizeof(arrays[a]) / sizeof(arrays[a][0])) {
            while (sb < sizeof(arrays[b]) / sizeof(arrays[b][0])) {
                sad += abs(arrays[a][sa] - arrays[b][sb]);
                sb++;
            }
            sa++;
            sb = 0;
        }
        printf("%lld\n", sad);
    }
    return 0;
}

